import { execFileSync } from "node:child_process";
import fs from "node:fs";
import path from "node:path";

const outDir = path.join("prisma", "migrations", "20260601120000_postgresql_baseline");
const outFile = path.join(outDir, "migration.sql");
const lockFile = path.join("prisma", "migrations", "migration_lock.toml");

fs.mkdirSync(outDir, { recursive: true });
fs.writeFileSync(
  lockFile,
  "# Please do not edit this file manually\n# It should be added in your version-control system (e.g., Git)\nprovider = \"postgresql\"\n",
  "utf8",
);

const sql = execFileSync(
  "npx",
  [
    "prisma",
    "migrate",
    "diff",
    "--from-empty",
    "--to-schema-datamodel",
    "prisma/schema.prisma",
    "--script",
  ],
  { encoding: "utf8", shell: true },
);

fs.writeFileSync(outFile, sql, "utf8");
console.log("Wrote", outFile, `(${sql.length} bytes)`);
